// ==================== VIETEXPRESS PRICE CALCULATOR ====================
// Dựa trên bảng giá tham khảo nội bộ ngày 26/04/2026
// Đầu ra: quoted_price, price_breakdown, suggested_surcharges, final_suggested_price, pricing_reasoning, Price_Base

const checkNode = $node["Check duplicate"];
if (!checkNode?.json?.newRow) {
  throw new Error('Không tìm thấy dữ liệu từ node "Check duplicate"');
}
const item = checkNode.json.newRow || {};

// ---------- Helper functions ----------
function toStr(v) {
  return v == null ? '' : String(v).trim();
}
function toNum(v, def = 0) {
  const n = parseFloat(toStr(v));
  return isNaN(n) ? def : n;
}

// Chuẩn hoá tên tỉnh (loại bỏ dấu chấm, dấu cách thừa)
function normalizeProv(p) {
  return toStr(p).toLowerCase().replace(/\./g, '').normalize('NFC');
}

// --------------------- ĐỊNH NGHĨA VÙNG THEO BẢNG GIÁ ---------------------
// Vùng 3: từ Hà Tĩnh trở ra Bắc
// Vùng 2: từ Quảng Ngãi đến Quảng Trị (miền Trung)
// Vùng 1: từ Gia Lai trở vào Nam
// Dựa vào danh sách các tỉnh điển hình (có thể mở rộng)
const regionNorth = new Set([
  'hà nội', 'hanoi', 'hải phòng', 'hai phong', 'quảng ninh', 'quang ninh',
  'bắc ninh', 'bac ninh', 'hưng yên', 'hung yen', 'hải dương', 'hai duong',
  'thái bình', 'thai binh', 'nam định', 'nam dinh', 'ninh bình', 'ninh binh',
  'hà nam', 'ha nam', 'hòa bình', 'hoa binh', 'sơn la', 'son la', 'điện biên', 'dien bien',
  'lai châu', 'lai chau', 'lào cai', 'lao cai', 'yên bái', 'yen bai', 'tuyên quang', 'tuyen quang',
  'phú thọ', 'phu tho', 'vĩnh phúc', 'vinh phuc', 'bắc giang', 'bac giang', 'lạng sơn', 'lang son',
  'cao bằng', 'cao bang', 'bắc kạn', 'bac kan', 'thái nguyên', 'thai nguyen', 'hà tĩnh', 'ha tinh'
]);

const regionCentral = new Set([
  'quảng bình', 'quang binh', 'quảng trị', 'quang tri', 'thừa thiên huế', 'thua thien hue', 'huế', 'hue',
  'đà nẵng', 'da nang', 'quảng nam', 'quang nam', 'quảng ngãi', 'quang ngai', 'bình định', 'binh dinh',
  'phú yên', 'phu yen', 'khánh hòa', 'khanh hoa', 'ninh thuận', 'ninh thuan', 'bình thuận', 'binh thuan'
]);

const regionSouth = new Set([
  'gia lai', 'gialai', 'kon tum', 'kontum', 'đắk lắk', 'dak lak', 'đắk nông', 'dak nong', 'lâm đồng', 'lam dong',
  'tp.hcm', 'tp hcm', 'tp hồ chí minh', 'hồ chí minh', 'ho chi minh', 'bình dương', 'binh duong',
  'đồng nai', 'dong nai', 'bà rịa vũng tàu', 'ba ria vung tau', 'tây ninh', 'tay ninh',
  'bình phước', 'binh phuoc', 'long an', 'long an', 'tiền giang', 'tien giang', 'bến tre', 'ben tre',
  'vĩnh long', 'vinh long', 'trà vinh', 'tra vinh', 'hậu giang', 'hau giang', 'sóc trăng', 'soc trang',
  'đồng tháp', 'dong thap', 'an giang', 'an giang', 'kiên giang', 'kien giang', 'cà mau', 'ca mau',
  'bạc liêu', 'bac lieu', 'cần thơ', 'can tho'
]);

function getRegion(province) {
  const norm = normalizeProv(province);
  if (regionNorth.has(norm)) return 'Bắc';   // Vùng 3
  if (regionCentral.has(norm)) return 'Trung'; // Vùng 2
  if (regionSouth.has(norm)) return 'Nam';    // Vùng 1
  // fallback heuristic
  if (/^(hải|hà|hưng|thái|nam|ninh|bắc|cao|lạng|tuyên|phú|vĩnh|yên)/i.test(norm)) return 'Bắc';
  if (/^(quảng|huế|đà|bình|phú|khánh|ninh|thuận)/i.test(norm)) return 'Trung';
  return 'Nam';
}

// Phân loại tuyến đường
function classifyRoute(origin, dest) {
  if (!origin || !dest) return { label: 'Không xác định', key: 'unknown' };
  const oNorm = normalizeProv(origin);
  const dNorm = normalizeProv(dest);
  if (oNorm === dNorm) return { label: 'Nội tỉnh', key: 'noi_tinh' };
  const regO = getRegion(origin);
  const regD = getRegion(dest);
  if (regO === regD) return { label: 'Nội vùng', key: 'noi_vung' };
  const pair = [regO, regD].sort().join('-');
  // Liên vùng: Bắc-Trung hoặc Trung-Nam
  if (pair === 'Bắc-Trung' || pair === 'Nam-Trung') return { label: 'Liên vùng', key: 'lien_vung' };
  // Liên tỉnh: Bắc-Nam
  return { label: 'Liên tỉnh', key: 'lien_tinh' };
}

// Trọng lượng thể tích
function getVolumetricWeight(dimStr) {
  if (!dimStr) return 0;
  const parts = dimStr.split('x').map(p => parseFloat(p.trim()));
  if (parts.length !== 3 || parts.some(isNaN)) return 0;
  const [d, w, h] = parts;
  return (d * w * h) / 5000;
}

// Làm tròn theo dịch vụ
function roundChargeable(w, svc) {
  if (svc === 'ltl' || svc === 'express') return Math.ceil(w * 2) / 2; // bước 0.5kg
  return Math.ceil(w); // bước 1kg
}

// Lấy khoảng cách (km)
let distanceKm = null;
try {
  const parsedDist = $node["Parse output Get Distance"]?.json;
  if (parsedDist && typeof parsedDist.distanceKm === 'number') distanceKm = parsedDist.distanceKm;
  else {
    const raw = $node["Get Distance"]?.json;
    const seg = raw?.features?.[0]?.properties?.segments?.[0];
    if (seg && seg.distance) distanceKm = seg.distance / 1000;
  }
} catch(e) { distanceKm = null; }
if (!distanceKm || isNaN(distanceKm)) distanceKm = 150; // mặc định

// ---------- Đọc dữ liệu đầu vào ----------
const serviceType = toStr(item.service_type).toLowerCase();
const actualWeight = toNum(item.weight);
const dimensions = toStr(item.dimensions);
const origin = toStr(item.origin);
const destination = toStr(item.destination);

// Tính trọng lượng tính cước
const volWeight = getVolumetricWeight(dimensions);
let chargeable = Math.max(actualWeight, volWeight);
chargeable = roundChargeable(chargeable, serviceType);

const route = classifyRoute(origin, destination);
// Key pricing: 'noi_tinh', 'noi_vung' (nội miền), 'lien_vung' (liên miền) – dùng cho LTL/Express
function pricingKeyForRoute(routeKey) {
  if (routeKey === 'noi_tinh') return 'noi_tinh';
  if (routeKey === 'noi_vung') return 'noi_vung';
  // liên vùng + liên tỉnh đều dùng bảng "liên miền"
  return 'lien_vung';
}
const pricingKey = pricingKeyForRoute(route.key);

// ---------- BẢNG GIÁ ----------
const LTL_TABLE = {
  '0-2': { noi_tinh: 28000, noi_vung: 36000, lien_vung: 52000 },
  '2-5': { noi_tinh: 40000, noi_vung: 55000, lien_vung: 78000 },
  '5-10': { noi_tinh: 62000, noi_vung: 84000, lien_vung: 118000 },
  '10-20': { noi_tinh: 95000, noi_vung: 130000, lien_vung: 180000 }
};
const LTL_EXTRA = { noi_tinh: 7500, noi_vung: 9500, lien_vung: 12500 };

const EXPRESS_TABLE = {
  '0-2': { noi_tinh: 45000, noi_vung: 65000, lien_vung: 95000 },
  '2-5': { noi_tinh: 65000, noi_vung: 95000, lien_vung: 138000 },
  '5-10': { noi_tinh: 95000, noi_vung: 140000, lien_vung: 205000 },
  '10-20': { noi_tinh: 145000, noi_vung: 210000, lien_vung: 310000 }
};
const EXPRESS_EXTRA = { noi_tinh: 12000, noi_vung: 15000, lien_vung: 20000 };

// FTL: chọn xe theo tải trọng (kg)
function pickVehicle(weightKg) {
  if (weightKg <= 1000) return { opening: 350000, perKm: 11000, name: 'Xe 1 tấn' };
  if (weightKg <= 1500) return { opening: 500000, perKm: 14000, name: 'Xe 1.5 tấn' };
  if (weightKg <= 2500) return { opening: 700000, perKm: 17000, name: 'Xe 2.5 tấn' };
  return { opening: 1150000, perKm: 22000, name: 'Xe 5 tấn' };
}

// ---------- TÍNH GIÁ CƠ BẢN (Price_Base) ----------
let Price_Base = 0;
let breakdown = { service: serviceType, chargeable_kg: chargeable, route: route.label };
let vehicleInfo = null;

if (serviceType === 'ltl') {
  let base = 0;
  if (chargeable <= 2) base = LTL_TABLE['0-2'][pricingKey];
  else if (chargeable <= 5) base = LTL_TABLE['2-5'][pricingKey];
  else if (chargeable <= 10) base = LTL_TABLE['5-10'][pricingKey];
  else if (chargeable <= 20) base = LTL_TABLE['10-20'][pricingKey];
  else base = LTL_TABLE['10-20'][pricingKey] + (chargeable - 20) * LTL_EXTRA[pricingKey];
  Price_Base = Math.round(base);
  breakdown.table = 'LTL';
} 
else if (serviceType === 'express') {
  let base = 0;
  if (chargeable <= 2) base = EXPRESS_TABLE['0-2'][pricingKey];
  else if (chargeable <= 5) base = EXPRESS_TABLE['2-5'][pricingKey];
  else if (chargeable <= 10) base = EXPRESS_TABLE['5-10'][pricingKey];
  else if (chargeable <= 20) base = EXPRESS_TABLE['10-20'][pricingKey];
  else base = EXPRESS_TABLE['10-20'][pricingKey] + (chargeable - 20) * EXPRESS_EXTRA[pricingKey];
  Price_Base = Math.round(base);
  breakdown.table = 'EXPRESS';
}
else if (serviceType === 'ftl') {
  const vehicle = pickVehicle(chargeable);
  vehicleInfo = vehicle;
  const minKm = (route.key === 'noi_tinh') ? 15 : 30;
  const km = Math.max(distanceKm, minKm);
  const price = vehicle.opening + km * vehicle.perKm;
  Price_Base = Math.round(price);
  breakdown.table = 'FTL';
  breakdown.vehicle = vehicle.name;
  breakdown.km = km;
}
else if (serviceType === 'cold') {
  const vehicle = pickVehicle(chargeable);
  vehicleInfo = vehicle;
  const minKm = (route.key === 'noi_tinh') ? 15 : 30;
  const km = Math.max(distanceKm, minKm);
  const baseFTL = vehicle.opening + km * vehicle.perKm;
  // Mặc định nhiệt độ 2-8°C => hệ số 1.30 (có thể đọc từ item.cold_temp nếu có)
  const tempFactor = 1.30;
  const coldSurcharge = (km < 150) ? 180000 : 350000;
  const price = baseFTL * tempFactor + coldSurcharge;
  Price_Base = Math.round(price);
  breakdown.table = 'COLD';
  breakdown.vehicle = vehicle.name;
  breakdown.km = km;
  breakdown.temp_factor = tempFactor;
  breakdown.cold_surcharge = coldSurcharge;
}
else if (serviceType === '3pl') {
  // Theo bảng 3.5: nhập kho 3000/kg + picking 2500 + packing 8000
  const storage = chargeable * 3000;
  const picking = 2500;
  const packing = 8000;
  Price_Base = Math.round(storage + picking + packing);
  breakdown.table = '3PL';
}
else if (serviceType === 'doc') {
  // Giá tư vấn bộ chứng từ cơ bản
  Price_Base = 120000;
  breakdown.table = 'DOC';
}
else {
  Price_Base = 0;
  breakdown.error = 'Dịch vụ không hỗ trợ';
}

// ---------- TÍNH PHỤ PHÍ (surcharges) ----------
// Đọc các flag từ item (có thể có hoặc không)
const codValue = toNum(item.cod_value);
const isRemote = toStr(item.remote_area) === 'true' || item.remote_area === true;
const isFragile = toStr(item.fragile) === 'true' || item.fragile === true;
const isAfterHours = toStr(item.after_hours) === 'true' || item.after_hours === true;
const isWeekendHoliday = toStr(item.weekend_holiday) === 'true' || item.weekend_holiday === true;
const liftTruckHours = toNum(item.lift_truck_hours);
const monthlyOrders = toNum(item.monthly_orders); // dùng cho chiết khấu

let surcharges = {
  cod_fee: 0,
  remote_surcharge: 0,
  fragile_surcharge: 0,
  after_hours_surcharge: 0,
  weekend_holiday_surcharge: 0,
  lift_truck_fee: 0,
  discount: 0
};

// 1. Phí COD: 0.8% giá trị COD, tối thiểu 15,000
if (codValue > 0) {
  surcharges.cod_fee = Math.max(codValue * 0.008, 15000);
}

// 2. Khu vực khó giao: +10% đến +20% cước cơ bản (lấy 15% làm mặc định)
if (isRemote) {
  surcharges.remote_surcharge = Math.round(Price_Base * 0.15);
}

// 3. Hàng dễ vỡ: +35,000 đến 120,000 (lấy 70,000 mặc định)
if (isFragile) {
  surcharges.fragile_surcharge = 70000;
}

// 4. Giao ngoài giờ (sau 20:00): +80,000
if (isAfterHours) {
  surcharges.after_hours_surcharge = 80000;
}

// 5. Giao cuối tuần/ngày lễ: +15% cước cơ bản
if (isWeekendHoliday) {
  surcharges.weekend_holiday_surcharge = Math.round(Price_Base * 0.15);
}

// 6. Nâng/hạ bằng xe nâng: 250,000/giờ
if (liftTruckHours > 0) {
  surcharges.lift_truck_fee = Math.round(250000 * liftTruckHours);
}

// 7. Chiết khấu theo sản lượng tháng
let discountPercent = 0;
if (monthlyOrders >= 500) discountPercent = 0.10;
else if (monthlyOrders >= 200) discountPercent = 0.06;
else if (monthlyOrders >= 50) discountPercent = 0.03;
surcharges.discount = -Math.round(Price_Base * discountPercent);

// Tổng phụ phí (cộng dồn, discount là số âm)
let totalSurcharges = 0;
for (let key in surcharges) {
  if (key !== 'discount') totalSurcharges += surcharges[key];
}
totalSurcharges += surcharges.discount; // discount âm

const final_suggested_price = Math.max(0, Price_Base + totalSurcharges);

// Xây dựng pricing_reasoning
const reasoningLines = [];
reasoningLines.push(`Dịch vụ: ${serviceType.toUpperCase()}`);
reasoningLines.push(`Trọng lượng tính cước: ${chargeable} kg (thực tế ${actualWeight} kg, thể tích ${volWeight.toFixed(2)} kg)`);
reasoningLines.push(`Tuyến: ${route.label} (${origin} → ${destination}) → dùng bảng ${pricingKey === 'lien_vung' ? 'liên miền' : pricingKey}`);
reasoningLines.push(`Giá cơ bản (Price_Base): ${Price_Base.toLocaleString()} VND`);
if (surcharges.cod_fee > 0) reasoningLines.push(`+ Phí COD (0.8%): ${Math.round(surcharges.cod_fee).toLocaleString()} VND`);
if (surcharges.remote_surcharge > 0) reasoningLines.push(`+ Phụ phí khu vực khó giao: ${surcharges.remote_surcharge.toLocaleString()} VND`);
if (surcharges.fragile_surcharge > 0) reasoningLines.push(`+ Hàng dễ vỡ: ${surcharges.fragile_surcharge.toLocaleString()} VND`);
if (surcharges.after_hours_surcharge > 0) reasoningLines.push(`+ Giao ngoài giờ: ${surcharges.after_hours_surcharge.toLocaleString()} VND`);
if (surcharges.weekend_holiday_surcharge > 0) reasoningLines.push(`+ Giao cuối tuần/lễ: ${surcharges.weekend_holiday_surcharge.toLocaleString()} VND`);
if (surcharges.lift_truck_fee > 0) reasoningLines.push(`+ Xe nâng (${liftTruckHours}h): ${surcharges.lift_truck_fee.toLocaleString()} VND`);
if (discountPercent > 0) reasoningLines.push(`- Chiết khấu ${discountPercent*100}%: ${(-surcharges.discount).toLocaleString()} VND`);
reasoningLines.push(`Tổng phụ phí: ${totalSurcharges.toLocaleString()} VND`);
reasoningLines.push(`Giá đề xuất cuối cùng: ${final_suggested_price.toLocaleString()} VND (chưa VAT)`);

const pricing_reasoning = reasoningLines.join('\n');

// ---------- TRẢ VỀ KẾT QUẢ ----------
const output = {
  ...item,
  quoted_price: final_suggested_price,          // giá cuối cùng (bao gồm phụ phí và chiết khấu)
  price_breakdown: breakdown,
  suggested_surcharges: surcharges,
  final_suggested_price: final_suggested_price,
  pricing_reasoning: pricing_reasoning,
  Price_Base: Price_Base,                       // giá cơ bản trước phụ phí
  chargeable_weight: chargeable,
  distance_km: distanceKm,
  route_classification: {
    label: route.label,
    key: route.key,
    pricingKey: pricingKey
  }
};

return output;

// Chạy ở chế độ "Run Once for All Items"
const allInputs = $input.all();

if (allInputs.length < 2) {
  // Không đủ dữ liệu (cần ít nhất 1 từ webhook + 1 từ DB)
  return {
    duplicate: false,
    newRow: allInputs[0]?.json || null,
    oldRows: []
  };
}

// Row mới từ webhook (phần tử đầu tiên)
const newRow = allInputs[0].json;

// Các row cũ từ database (từ phần tử thứ 2 trở đi)
const oldRows = allInputs.slice(1).map(item => item.json);

// Hàm tạo fingerprint từ các trường cần so sánh
function getFingerprint(row) {
  const fields = ['service_type', 'origin', 'destination', 'weight', 'dimensions', 'customer_name','customer_phone','customer_email'];
  return fields.map(field => {
    let value = row[field];
    if (value === null || value === undefined) value = '';
    return String(value).trim().toLowerCase();
  }).join('|');
}

const newFingerprint = getFingerprint(newRow);
const isDuplicate = oldRows.some(oldRow => getFingerprint(oldRow) === newFingerprint);

// Trả về kết quả kèm theo oldRows để xử lý tiếp trong nhánh false
return {
  duplicate: isDuplicate,
  newRow: newRow,
  oldRows: oldRows   // <- đây là toàn bộ row của Get a row
};

// Code node – chạy chế độ "Run Once for Each Item"
const item = $input.first().json;

// Parse an toàn chuỗi JSON
let parsed = null;
try {
    // Xử lý escape ký tự
    const cleaned = item.output.replace(/\\n/g, '\n').replace(/\\"/g, '"');
    parsed = JSON.parse(cleaned);
} catch (err) {
    parsed = { error: `Parse failed: ${err.message}`, raw: item.output };
}

// Trả về object đã parse (clean)
return parsed;

// Lấy item đầu tiên từ input (vì webhook trả về mảng 1 phần tử)
const item = $input.first().json;

// Dữ liệu nằm trong item.body
const body = item.body;

// Tạo object đơn giản chứa các thông tin cần thiết
const output = {
  // Thông tin báo giá
  quoteId: body.quoteId,
  quoteCode: body.quoteCode,
  status: body.status,
  quotedPrice: body.quotedPrice,
  approvedAt: body.approvedAt,
  message: body.message,

  // Thông tin khách hàng
  customer: {
    fullName: body.customer.fullName,
    phone: body.customer.phone,
    email: body.customer.email,
    company: body.customer.company
  },

  // Thông tin đơn hàng
  quote: {
    serviceType: body.quote.serviceType,
    origin: body.quote.origin,
    destination: body.quote.destination,
    weight: body.quote.weight,
    dimensions: body.quote.dimensions,
    note: body.quote.note
  },

  // Định dạng giá tiền cho dễ đọc (ví dụ: 250.000 VND)
  formattedPrice: new Intl.NumberFormat('vi-VN').format(body.quotedPrice) + ' VND',

  // Định dạng ngày giờ duyệt
  formattedApprovedAt: new Date(body.approvedAt).toLocaleString('vi-VN')
};

// Trả về object này để các node tiếp theo sử dụng
return output;

const raw = $json.data ? JSON.parse($json.data) : $json;

const feature = raw.features?.[0];
const segment = feature?.properties?.segments?.[0];
const summary = feature?.properties?.summary;

const distanceMeters =
  summary?.distance ||
  segment?.distance ||
  0;

const durationSeconds =
  summary?.duration ||
  segment?.duration ||
  0;

return [
  {
    json: {
      distanceMeters,
      distanceKm: Number((distanceMeters / 1000).toFixed(1)),

      durationSeconds,
      durationMinutes: Number((durationSeconds / 60).toFixed(1)),
      durationHours: Number((durationSeconds / 3600).toFixed(2)),

      routeSummary: {
        distanceKm: Number((distanceMeters / 1000).toFixed(1)),
        durationHours: Number((durationSeconds / 3600).toFixed(2)),
      }
    }
  }
];

// =========================
// Merge Final Suggested Price
// =========================

// Lấy data từ node pricing rule-based
const pricing =
  $node["Calculate Reference Price"].json;

// Lấy data AI suggestion đã parse
const ai =
  $json;

// Giá cơ bản từ rule engine
const Price_Base =
  Number(pricing.Price_Base || 0);

// Tổng surcharge AI gợi ý
const aiSurcharge =
  Number(ai.total_suggested_surcharge || 0);

// Final price
const final_price =
  Price_Base + aiSurcharge;

// Merge output
return {
  ...pricing,

  ai_suggested_surcharges:
    ai.suggested_surcharges || [],

  ai_total_surcharge:
    aiSurcharge,

  ai_risk_level:
    ai.risk_level || "unknown",

  ai_pricing_notes:
    ai.pricing_notes || [],

  final_price,

  final_price_formatted:
    new Intl.NumberFormat('vi-VN')
      .format(final_price) + ' VND'
};
